<script setup lang="ts">
import type { CoachHelpBlock } from '~~/shared/types/coach'
import type { CoachHelpContentValues } from '~~/shared/utils/coach-help'
import { automaticOrthographyHelpKind, renderCoachHelpContent } from '~~/shared/utils/coach-help'
import { sanitizeCoachHtml } from '~~/shared/utils/safe-html'

const props = defineProps<{
  block: CoachHelpBlock
  values: CoachHelpContentValues
}>()

const activeChildren = computed(() => (props.block.children || []).filter(child => child.isActive))
const isRadicalBlock = computed(() => ['{contextualBaseHelp}', '{completeAdviceHelp}'].includes(props.block.content.trim()))
const isDefinitionBlock = computed(() => props.block.content.trim() === '{definitionHelp}')
const isCondensedTenseRuleBlock = computed(() => props.block.content.trim() === '{condensedTenseRuleHelp}')
const isResultBlock = computed(() => props.block.title.trim().normalize('NFD').replace(/\p{Diacritic}/gu, '').toLocaleLowerCase('fr') === 'resultat')
const orthographyKind = computed(() => automaticOrthographyHelpKind(props.block))
const renderedTitle = computed(() => isDefinitionBlock.value
  ? 'Définition'
  : isRadicalBlock.value
    ? ''
    : props.block.title)
const renderedContent = computed(() => sanitizeCoachHtml(renderCoachHelpContent(props.block.content, props.values, props.block.explanationApproach || 'cif-falc')))
</script>

<template>
  <section class="coach-help-block" :class="[`coach-help-block--${block.type}`, { 'coach-help-block--orthography': orthographyKind, 'coach-help-block--radical': isRadicalBlock, 'coach-help-block--definition': isDefinitionBlock, 'coach-help-block--result': isResultBlock }]">
    <h3 v-if="renderedTitle">
      <span v-if="orthographyKind" class="coach-help-block__letter" aria-hidden="true">{{ orthographyKind.toUpperCase() }}</span>
      <span v-else-if="isDefinitionBlock" class="coach-help-block__info-icon" aria-hidden="true">i</span>
      {{ renderedTitle }}
    </h3>
    <div
      v-if="renderedContent"
      class="coach-help-block__content"
      :class="{ 'coach-help-block__content--radical': isRadicalBlock, 'coach-help-block__content--condensed-tense-rule': isCondensedTenseRuleBlock }"
      v-html="renderedContent"
    />
    <div v-if="activeChildren.length" class="coach-help-block__children">
      <CoachHelpBlockView
        v-for="(child, index) in activeChildren"
        :key="`${child.id}-${index}`"
        :block="child"
        :values="values"
      />
    </div>
  </section>
</template>

